const payload = $json.body ?? $json;
const detailLevel = String(payload.detail_level ?? payload.detailLevel ?? 'brief').toLowerCase();
const messageId = String(payload.message_id ?? payload.messageId ?? '').trim();
const threadId = String(payload.thread_id ?? payload.threadId ?? '').trim();
const sender = String(payload.sender ?? '').trim();
const subject = String(payload.subject ?? '').trim();
const mailboxScope = String(payload.mailboxScope ?? payload.mailbox_scope ?? 'default').toLowerCase();
const requestedLimit = Number(payload.limit ?? 20);
const limit = Number.isFinite(requestedLimit) && requestedLimit > 0 ? Math.min(requestedLimit, 30) : 20;
let query = String(payload.search_query ?? payload.searchQuery ?? '').trim();
if (!query && subject) {
  query = `subject:"${subject}" newer_than:30d`;
}
if (!query && sender) {
  query = `from:${sender} newer_than:30d`;
}
if (!query) {
  query = 'newer_than:30d';
}
return [{ json: { detail_level: detailLevel === 'full' ? 'full' : 'brief', message_id: messageId, thread_id: threadId, sender, subject, search_query: query, mailboxScope, limit } }];

const request = $('Normalize Thread Request').first().json;
const candidates = $input.all().map((item) => item.json).filter((mail) => mail && (mail.id || mail.subject || mail.threadId));

if (!candidates.length) {
  return [{ json: { action: 'gmail-thread', found: false, reply: '요청한 조건에 맞는 메일 스레드를 찾지 못했습니다. 제목, 스레드 ID, 조회 범위를 더 구체적으로 알려주세요.' } }];
}

const readHeader = (headers, key) => {
  if (!Array.isArray(headers)) return '';
  const matched = headers.find((header) => String(header.name || '').toLowerCase() === key.toLowerCase());
  return matched?.value || '';
};

const normalizeText = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const sortTime = (mail) => {
  const dateText = String(mail.date || readHeader(mail.headers, 'Date') || '');
  const parsed = new Date(dateText);
  return Number.isNaN(parsed.getTime()) ? 0 : parsed.getTime();
};

const pick = (() => {
  if (request.message_id) {
    const matched = candidates.find((mail) => String(mail.id || '') === String(request.message_id));
    if (matched) return matched;
  }
  if (request.thread_id) {
    const matched = candidates.find((mail) => String(mail.threadId || '') === String(request.thread_id));
    if (matched) return matched;
  }
  return candidates[0];
})();

const targetThreadId = String(request.thread_id || pick.threadId || '');
const threadMessages = (targetThreadId ? candidates.filter((mail) => String(mail.threadId || '') === targetThreadId) : [pick])
  .sort((a, b) => sortTime(a) - sortTime(b));

if (!threadMessages.length) {
  return [{ json: { action: 'gmail-thread', found: false, reply: '요청한 조건에 맞는 메일 스레드를 찾지 못했습니다. 제목, 스레드 ID, 조회 범위를 더 구체적으로 알려주세요.' } }];
}

const items = threadMessages.map((mail, index) => {
  const headers = Array.isArray(mail.headers) ? mail.headers : [];
  const subject = normalizeText(mail.subject || readHeader(headers, 'Subject') || '(제목 없음)');
  const sender = normalizeText(typeof mail.from === 'string' ? mail.from : (mail.from?.text || readHeader(headers, 'From') || '발신자 미상'));
  const to = normalizeText(typeof mail.to === 'string' ? mail.to : (mail.to?.text || readHeader(headers, 'To') || ''));
  const date = normalizeText(mail.date || readHeader(headers, 'Date') || '');
  const snippet = normalizeText(mail.snippet || '');
  const body = normalizeText(mail.text || '');
  return { index: index + 1, messageId: String(mail.id || ''), threadId: String(mail.threadId || ''), sender, to, subject, date, snippet, body, internalDate: date ? String(new Date(date).getTime()) : '', unread: Array.isArray(mail.labelIds) ? mail.labelIds.includes('UNREAD') : false };
});

const headerSubject = items.find((item) => item.subject)?.subject || '';
return [{ json: { action: 'gmail-thread', found: true, subject: headerSubject, threadId: targetThreadId, selectedMessageId: String(request.message_id || pick.id || ''), messageCount: items.length, items, reply: `메일 스레드 ${items.length}건을 찾았습니다.` } }];
